500000000000001;page-break-after:avoid;orphans:2;widows:2;text-align:left}h2{padding-top:10pt;color:#4f81bd;font-weight:700;font-size:13pt;padding-bottom:0pt;font-family:"Cambria";line-height:1.1500000000000001;page-break-after:avoid;orphans:2;widows:2;text-align:left}h3{padding-top:10pt;color:#4f81bd;font-weight:700;font-size:11pt;padding-bottom:0pt;font-family:"Cambria";line-height:1.1500000000000001;page-break-after:avoid;orphans:2;widows:2;text-align:left}h4{padding-top:10pt;color:#4f81bd;font-weight:700;font-size:11pt;padding-bottom:0pt;font-family:"Cambria";line-height:1.1500000000000001;page-break-after:avoid;font-style:italic;orphans:2;widows:2;text-align:left}h5{padding-top:11pt;color:#000000;font-weight:700;font-size:11pt;padding-bottom:2pt;font-family:"Calibri";line-height:1.1500000000000001;page-break-after:avoid;orphans:2;widows:2;text-align:left}h6{padding-top:10pt;color:#000000;font-weight:700;font-size:10pt;padding-bottom:2pt;font-family:"Calibri";line-height:1.1500000000000001;page-break-after:avoid;orphans:2;widows:2;text-align:left}</style></head><body class="c56"><p class="c51 subtitle" id="h.43fta1mlxud"><span class="c49">Manual Introducci&oacute;n GDE</span></p><p class="c2"><span class="c12"></span></p><p class="c62"><span class="c43"><a class="c17" href="#h.dqrm20vwqprr">1. </a></span><span class="c43"><a class="c17" href="#h.dqrm20vwqprr">INTRODUCCI&Oacute;N GDE</a></span><span class="c43">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span class="c43"><a class="c17" href="#h.dqrm20vwqprr">3</a></span></p><p class="c27"><span class="c12"><a class="c17" href="#h.5chluiv7dy4z">2. ACCESOS</a></span><span class="c12">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span class="c12"><a class="c17" href="#h.5chluiv7dy4z">4</a></span></p><p class="c6"><span class="c12"><a class="c17" href="#h.2n20gi8ihnwi">SOLICITUD DE USUARIOS</a></span><span class="c12">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span class="c12"><a class="c17" href="#h.2n20gi8ihnwi">4</a></span></p><p class="c27"><span class="c12"><a class="c17" href="#h.yojffkfjpy59">3. EE &ndash; EXPEDIENTE &nbsp;DIGITAL</a></span><span class="c12">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span class="c12"><a class="c17" href="#h.yojffkfjpy59">5</a></span></p><p class="c6"><span class="c12"><a class="c17" href="#h.h45emvvxjb72">INICIAR UN EXPEDIENTE</a></span><span class="c12">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span class="c12"><a class="c17" href="#h.h45emvvxjb72">5</a></span></p><p class="c50"><span class="c12"><a class="c17" href="#h.3pzmhdr559ln">REPARTICIONES Y SECTORES PARA CARATULAR EN MDSyT</a></span><span class="c12">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span class="c12"><a class="c17" href="#h.3pzmhdr559ln">7</a></span></p><p class="c6"><span class="c12"><a class="c17" href="#h.kovm2tfglw0t">CARATULAR EXPEDIENTE SOLICITADO</a></span><span class="c12">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span class="c12"><a class="c17" href="#h.kovm2tfglw0t">8</a></span></p><p class="c6"><span class="c12"><a class="c17" href="#h.86q0cswzawra">VINCULAR DOCUMENTOS</a></span><span class="c12">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span class="c12"><a class="c17" href="#h.86q0cswzawra">9</a></span></p><p class="c6"><span><a class="c17" href="#h.1intkvirxpth">PROSECUCI&Oacute;N DEL TR&Aacute;MITE</a></span><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span><a class="c17" href="#h.1intkvirxpth">11</a></span></p><p class="c52"><span><a class="c17" href="#h.y83zgn8ze0fl">VINCULACI&Oacute;N DE PASE EN EXPEDIENTE F&Iacute;SICO</a></span><span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span><span><a class="c17" href="#h.y83zgn8ze0fl">12</a></span></p><p class="c2"><span class="c12"></span></p><p class="c34 c13" id="h.w6tnhcbjym0h"><span class="c47 c43"></span></p><p class="c34" id="h.dqrm20vwqprr"><span class="c43 c47">1.INTRODUCCI&Oacute;N GDE </span></p><p class="c21 c13"><span class="c1"></span></p><p class="c21"><span class="c1">GDE es una plataforma inform&aacute;tica que permite la gesti&oacute;n digital de todos los tr&aacute;mites de la Administraci&oacute;n, persiguiendo como objetivo en su implementaci&oacute;n despapelizar el procedimiento administrativo, eficientizar la gesti&oacute;n administrativa y facilitar la generaci&oacute;n electr&oacute;nica, registro y archivo de la documentaci&oacute;n. </span></p><p class="c21"><span class="c1">Esta plataforma est&aacute; implementada en la Administraci&oacute;n Central de Naci&oacute;n y a trav&eacute;s de un Convenio con el Ministerio de Modernizaci&oacute;n es distribuida a las Provincias, Municipios y otros Organismos P&uacute;blicos con el fin de generar una red de comunicaci&oacute;n digital para los tr&aacute;mites. </span></p><p class="c21"><span class="c1">Se compone de m&oacute;dulos relacionados entre s&iacute;. </span></p><p class="c21"><span class="c1">La Provincia del Neuqu&eacute;n adhiri&oacute; a los siguientes: </span></p><p class="c21"><span class="c16">Escritorio &Uacute;nico (EU)</span><span class="c1">&nbsp;es la interfaz que permite navegar por todos los m&oacute;dulos que integran el sistema GDE, por ello, se lo considera la cara visible de GDE. Desde EU se configura el acceso a la plataforma de Gesti&oacute;n Documental Electr&oacute;nica (GDE). Adem&aacute;s, muestra un resumen de todas las tareas pendientes que el agente tiene en cada m&oacute;dulo y las organiza seg&uacute;n un rango de antig&uuml;edad en d&iacute;as. Asimismo, a trav&eacute;s del EU cada superior jer&aacute;rquico puede visualizar la carga de trabajo del personal que tiene a cargo en su sector. </span></p><p class="c21"><span class="c16">Generador Electr&oacute;nico de Documentos Oficiales (GEDO):</span><span class="c1">&nbsp;es el m&oacute;dulo que permite generar, registrar y consultar todos los documentos oficiales electr&oacute;nicos necesarios para vincularlos a una actuaci&oacute;n </span></p><p class="c21"><span class="c16">Comunicaciones Oficiales (CCO):</span><span class="c1">&nbsp;es el m&oacute;dulo que permite generar, registrar y consultar documentos comunicables. </span></p><p class="c21"><span class="c16">Expediente Electr&oacute;nico (EE):</span><span class="c1">&nbsp;es el m&oacute;dulo que se utiliza para la caratulaci&oacute;n, vinculaci&oacute;n de documentos, pases y consultas de expedientes electr&oacute;nicos.</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 636.10px; height: 336.40px;"><img alt="" src="images/image6.png" style="width: 636.10px; height: 336.40px; margin-left: 0.00px; margin-top: 0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c10 c13" id="h.e9rjg152oh28"><span class="c45 c43"></span></p><p class="c10" id="h.ecffbq1cl75q"><span class="c43 c45">2. ACCESOS</span></p><p class="c7 c13"><span class="c1"></span></p><p class="c7"><span class="c29 c37">P&aacute;gina oficial de GDE, donde se encuentra toda la documentaci&oacute;n relacionada a novedades, legislaci&oacute;n y manuales.</span></p><p class="c9"><span class="c46 c29 c61"><a class="c17" href="https://www.google.com/url?q=https://gde.neuquen.gov.ar/&amp;sa=D&amp;source=editors&amp;ust=1647874987538947&amp;usg=AOvVaw2XHONGmqeqdhoj2OcAsXMI">https://gde.neuquen.gov.ar/</a></span></p><p class="c7 c13"><span class="c1"></span></p><p class="c7"><span class="c29 c37">Para acceder a GDE entorno de producci&oacute;n ingresar a con tu usuario y contrase&ntilde;a a:&nbsp;</span></p><p class="c9"><span class="c44 c29 c61"><a class="c17" href="https://www.google.com/url?q=https://eu.gde.neuquen.gov.ar/&amp;sa=D&amp;source=editors&amp;ust=1647874987539642&amp;usg=AOvVaw24mWRdzjdrgQohbAuap7uo">https://eu.gde.neuquen.gov.ar/</a></span></p><p class="c10 c13" id="h.rl8a9tv54rat"><span class="c19"></span></p><p class="c10" id="h.1oe5eczaluc6"><span class="c19">SOLICITUD DE USUARIOS</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c21"><span class="c1">Los usuarios para GDE son creados autom&aacute;ticamente para cada agente una vez finalizada y aprobada la capacitaci&oacute;n dictada desde el Ministerio de Desarrollo Social y Trabajo.</span></p><p class="c7"><span class="c1">O bien el director o responsable del sector deber&aacute; solicitarlo v&iacute;a mail, enviando los siguientes datos:</span></p><ul class="c48 lst-kix_list_1-0 start"><li class="c24 c31 li-bullet-0"><span class="c1">Nombre completo y Apellido.</span></li><li class="c31 c24 li-bullet-0"><span class="c1">N&deg; de Legajo.</span></li><li class="c31 c24 li-bullet-0"><span class="c1">N&deg; de DNI.</span></li><li class="c31 c24 li-bullet-0"><span class="c1">Mail de contacto.</span></li><li class="c31 c24 li-bullet-0"><span class="c1">&Aacute;rea a la cual pertenece.</span></li><li class="c24 c59 li-bullet-0"><span class="c1">Funciones que desempe&ntilde;a.</span></li></ul><p class="c7 c13"><span class="c1"></span></p><p class="c7"><span class="c29 c37">Subsecretar&iacute;a De Familia: </span><span class="c46 c29"><a class="c17" href="mailto:informaticasubsefamilia@neuquen.gov.ar">informaticasubsefamilia@neuquen.gov.ar</a></span></p><p class="c7"><span class="c29 c37">Subsecretar&iacute;a De Desarrollo Social: </span><span class="c29 c46"><a class="c17" href="mailto:informaticasubsedesarrollo@neuquen.gov.ar">informaticasubsedesarrollo@neuquen.gov.ar</a></span><span class="c1">&nbsp;</span></p><p class="c7"><span class="c29 c37">Subsecretar&iacute;a de Trabajo. </span><span class="c29 c44"><a class="c17" href="mailto:asistenciatrabajo@neuquen.gov.ar">asistenciatrabajo@neuquen.gov.ar</a></span><span class="c29 c37">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></p><p class="c7"><span class="c29 c37">Coordinaci&oacute;n de enlace ministerial: </span><span class="c46 c29"><a class="c17" href="mailto:asistenciaenlace@neuquen.gov.ar">asistenciaenlace@neuquen.gov.ar</a></span><span class="c29 c37">&nbsp;</span></p><hr style="page-break-before:always;display:none;"><p class="c2"><span class="c1"></span></p><p class="c10" id="h.yojffkfjpy59"><span class="c45 c43">3. EE &ndash; EXPEDIENTE &nbsp;DIGITAL</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c21"><span class="c1">El m&oacute;dulo Expediente Electr&oacute;nico (EE) se utiliza para caratulaci&oacute;n, vinculaci&oacute;n de documentos, pases y consultas de expedientes electr&oacute;nicos. </span></p><p class="c21"><span class="c1">Todos los documentos que conformen un expediente electr&oacute;nico tendr&aacute;n que ser previamente generados en forma electr&oacute;nica a trav&eacute;s de los m&oacute;dulos Comunicaciones Oficiales (CCOO) &oacute; Generador de Documentos Oficiales (GEDO). Si los documentos estuvieran en papel u otro formato, deber&aacute;n ser digitalizados a trav&eacute;s de GEDO. </span></p><p class="c21"><span class="c1">Tambi&eacute;n hay documentos que se generan y vinculan a un expediente electr&oacute;nico al realizar determinadas operaciones en el m&oacute;dulo EE. Estos documentos se generan de forma autom&aacute;tica en el m&oacute;dulo GEDO sin que el usuario tenga que realizar una operaci&oacute;n adicional. </span></p><p class="c21"><span class="c1">Se puede vincular un documento a m&aacute;s de un expediente.</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c10" id="h.h45emvvxjb72"><span class="c19">INICIAR UN EXPEDIENTE</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c21"><span class="c1">La pesta&ntilde;a Buz&oacute;n Tareas muestra las tareas del usuario logueado en el sistema. Existen tres tipos de tareas que pueden efectuarse a trav&eacute;s de esta solapa del m&oacute;dulo de Expediente Electr&oacute;nico: </span></p><ul class="c48 lst-kix_list_2-0 start"><li class="c4 c24 li-bullet-0"><span class="c1">Crear nueva solicitud </span></li><li class="c4 c24 li-bullet-0"><span class="c1">Caratular interno </span></li><li class="c21 c24 li-bullet-0"><span class="c1">Caratular externo</span></li></ul><p class="c0"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.93px; height: 199.82px;"><img alt="" src="images/image2.png" style="width: 566.93px; height: 199.82px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c21 c13"><span class="c1"></span></p><p class="c21"><span class="c1">Para la solicitud de caratulaci&oacute;n de un expediente debe hacerse desde el bot&oacute;n &ldquo;CREAR NUEVA SOLICITUD&rdquo;</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.93px; height: 140.10px;"><img alt="" src="images/image4.png" style="width: 566.93px; height: 140.10px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c21 c13"><span class="c1"></span></p><p class="c21"><span class="c1">Una vez presionado se abrir&aacute; la siguiente pantalla</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.93px; height: 476.04px;"><img alt="" src="images/image3.png" style="width: 566.93px; height: 476.04px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c21 c13"><span class="c1"></span></p><p class="c21"><span class="c1">Se deben completar los campos de Motivo interno y Motivo externo que consta de una descripci&oacute;n del tr&aacute;mite a realizar. Deben ser lo m&aacute;s aclaratorios posibles y espec&iacute;ficos, se sugiere en el motivo externo no colocar informaci&oacute;n personal, como documentos, cuil, etc. El motivo externo es utilizado por los buscadores y es visible al p&uacute;blico.</span></p><p class="c21"><span class="c1">A continuaci&oacute;n se selecciona el tipo de expediente, interno o externo. </span></p><p class="c21 c13"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 315.20px; height: 262.40px;"><img alt="" src="images/image12.png" style="width: 315.20px; height: 262.40px; margin-left: 0.00px; margin-top: 0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c8 c13"><span class="c1"></span></p><p class="c21"><span class="c1">El m&oacute;dulo le permite al usuario solicitante sugerir el C&oacute;digo de Tr&aacute;mite, para ello se despliega el combo Tr&aacute;mite Sugerido y se elige la opci&oacute;n. &nbsp;Salvo casos excepcionales y previa coordinacion entre las areas, siempre se solicitara GENE 00004 &ndash; Expediente</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c21"><span class="c29">Para confirmar la operaci&oacute;n se debe cliquear sobre el bot&oacute;n </span><span class="c16">Solicitar caratulaci&oacute;n</span><span class="c1">. El bot&oacute;n Cancelar cancela la acci&oacute;n y redirige a la pantalla anterior. </span></p><p class="c21"><span class="c1">A continuaci&oacute;n se presentan dos opciones de destino para Enviar la solicitud de caratulaci&oacute;n: </span></p><ul class="c48 lst-kix_list_4-0 start"><li class="c4 c24 li-bullet-0"><span class="c1">A un usuario caratulador. </span></li><li class="c21 c24 li-bullet-0"><span class="c1">A una repartici&oacute;n y sector</span></li></ul><p class="c0"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.93px; height: 274.55px;"><img alt="" src="images/image5.png" style="width: 566.93px; height: 274.55px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c21 c13"><span class="c1"></span></p><p class="c21"><span class="c1">Una vez seleccionado el destino se presiona en el bot&oacute;n Enviar Solicitud. </span></p><p class="c21"><span class="c1">Las tareas de caratulaci&oacute;n se identifican en el Buz&oacute;n de Tareas con el nombre Iniciar Expediente. </span></p><p class="c21"><span class="c1">S&oacute;lo podr&aacute;n ser caratuladas por los usuarios con perfil de caratulador que lo tienen los usuarios de mesa de entrada.</span></p><p class="c10 c13" id="h.8ywniiyk5323"><span class="c41"></span></p><p class="c10" id="h.axjhk55f8m61"><span class="c19">REPARTICIONES Y SECTORES PARA CARATULAR EN MDSyT</span></p><p class="c10 c13" id="h.p1mxk9fhcttm"><span class="c41"></span></p><a id="t.fd45cb2b35e4a9427be15dceae6980e6e5f5d01b"></a><a id="t.0"></a><table class="c39"><tbody><tr class="c14"><td class="c57" colspan="1" rowspan="1"><p class="c36"><span class="c11">DETALLE</span></p></td><td class="c60" colspan="1" rowspan="1"><p class="c23"><span class="c11">REPARTICI&Oacute;N</span></p></td><td class="c20" colspan="1" rowspan="1"><p class="c23"><span class="c11">SECTOR</span></p></td></tr><tr class="c14"><td class="c35" colspan="1" rowspan="1"><p class="c36"><span class="c15">M/E Ministerio de Desarrollo Social y Trabajo</span></p></td><td class="c3" colspan="1" rowspan="1"><p class="c23"><span class="c5">LEGAL#MTDS</span></p></td><td class="c26" colspan="1" rowspan="1"><p class="c23"><span class="c5">PVD-MESA</span></p></td></tr><tr class="c14"><td class="c35" colspan="1" rowspan="1"><p class="c36"><span class="c15">M/E Subsecretar&iacute;a de Desarrollo Social</span></p></td><td class="c3" colspan="1" rowspan="1"><p class="c23"><span class="c5">LEGAL#SDS</span></p></td><td class="c26" colspan="1" rowspan="1"><p class="c23"><span class="c5">PVD-MESA</span></p></td></tr><tr class="c14"><td class="c35" colspan="1" rowspan="1"><p class="c36"><span class="c15">M/E Subsecretar&iacute;a de Familia</span></p></td><td class="c3" colspan="1" rowspan="1"><p class="c23"><span class="c5">LEGAL#SFAM</span></p></td><td class="c26" colspan="1" rowspan="1"><p class="c23"><span class="c5">PVD-MESA</span></p></td></tr><tr class="c14"><td class="c35" colspan="1" rowspan="1"><p class="c36"><span class="c15">M/E Subsecretar&iacute;a de Trabajo</span></p></td><td class="c3" colspan="1" rowspan="1"><p class="c23"><span class="c5">ST#MTDS</span></p></td><td class="c26" colspan="1" rowspan="1"><p class="c23"><span class="c5">PVD-MESA</span></p></td></tr></tbody></table><p class="c21 c13"><span class="c12"></span></p><hr style="page-break-before:always;display:none;"><p class="c2"><span class="c12"></span></p><p class="c10" id="h.kovm2tfglw0t"><span class="c19">CARATULAR EXPEDIENTE SOLICITADO</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c21"><span class="c1">El usuario responsable de la mesa de entrada, recibe la solicitud de caratulaci&oacute;n, dependiendo el tipo de env&iacute;o que realizo el solicitante.</span></p><p class="c21"><span class="c1">Si el env&iacute;o se hizo a la repartici&oacute;n/sector, el mismo estar disponible para adquirir dentro de la pesta&ntilde;a BUZ&Oacute;N GRUPAL, desde donde debe ser adquirido para su tramitaci&oacute;n.</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.93px; height: 100.01px;"><img alt="" src="images/image8.png" style="width: 566.93px; height: 100.01px; margin-left: 0.00px; margin-top: 0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c21 c13"><span class="c1"></span></p><p class="c21"><span class="c1">Si el env&iacute;o se hizo a un usuario espec&iacute;fico, o bien ya se adquiri&oacute; desde el buz&oacute;n grupal, estar&aacute; disponible dentro del BUZ&Oacute;N DE TAREAS. </span></p><p class="c21"><span class="c1">Para iniciar la caratulaci&oacute;n se debe seleccionar la acci&oacute;n tramitaci&oacute;n dentro de la tarea &ldquo;Iniciar Expediente&rdquo;</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.93px; height: 97.44px;"><img alt="" src="images/image7.png" style="width: 566.93px; height: 97.44px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c2"><span class="c1"></span></p><p class="c18"><span class="c1">Una vez seleccionado TRAMITAR se despliega el siguiente formulario, sobre el cual se debe Seleccionar el C&oacute;digo de Tr&aacute;mite del desplegable o dejar el sugerido por el solicitante de la car&aacute;tula. Adem&aacute;s se debe completar el campo Descripci&oacute;n Adicional del Tr&aacute;mite.</span></p><p class="c2"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.93px; height: 358.13px;"><img alt="" src="images/image11.png" style="width: 566.93px; height: 358.13px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c2"><span class="c1"></span></p><p class="c18"><span class="c1">Luego de presionar en el bot&oacute;n Caratular se visualizar&aacute; el n&uacute;mero del expediente generado. Al presionar en el bot&oacute;n OK se enviar&aacute; el Expediente Electr&oacute;nico al usuario solicitante.</span></p><p class="c2"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 336.00px; height: 167.20px;"><img alt="" src="images/image9.png" style="width: 336.00px; height: 167.20px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c10 c13" id="h.86q0cswzawra"><span class="c19"></span></p><p class="c10" id="h.r1qiacl6yam9"><span class="c19">VINCULAR DOCUMENTOS</span></p><p class="c10 c13" id="h.5e55ca6ssue5"><span class="c19"></span></p><p class="c21"><span class="c1">Una vez realizada la caratulaci&oacute;n por parte de las mesas de entrada, el expediente es autom&aacute;ticamente retornado al usuario solicitante. De esta manera ya est&aacute; listo para la vinculaci&oacute;n de documentos.</span></p><p class="c21"><span class="c1">La vinculaci&oacute;n de un documento es la asociaci&oacute;n entre un GEDO previamente generado y un Expediente Digital.</span></p><p class="c21"><span class="c1">Un EE adem&aacute;s de los documentos vinculados, posee GEDOs que se generan autom&aacute;ticamente y forman parte del mismo, como lo es la CAR&Aacute;TULA y el documento PROVIDENCIA que se genera en cada pase realizado.</span></p><p class="c21"><span class="c1">Para vincular un documento al expediente se deben ingresar los datos del n&uacute;mero GDE que le fue asignado cuando se cre&oacute;. Los datos a completar son:</span></p><ul class="c48 lst-kix_list_5-0 start"><li class="c4 c24 li-bullet-0"><span class="c29">Actuaci&oacute;n</span><span class="c1">: se carga la letra del documento. (EX)</span></li><li class="c4 c24 li-bullet-0"><span class="c1">A&ntilde;o: ingresar el a&ntilde;o de firma del documento.</span></li><li class="c4 c24 li-bullet-0"><span class="c1">N&uacute;mero: secuencia num&eacute;rica asignada por el sistema GDE.</span></li><li class="c4 c24 li-bullet-0" id="h.gjdgxs"><span class="c1">Ecosistema: Seleccionar a qu&eacute; tipo de ecosistema pertenece el documento. (NEU)</span></li><li class="c21 c24 li-bullet-0"><span class="c1">Repartici&oacute;n: donde se firm&oacute; el documento.</span></li></ul><p class="c0"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.93px; height: 108.34px;"><img alt="" src="images/image10.png" style="width: 566.93px; height: 108.34px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c21 c13"><span class="c12"></span></p><p class="c21"><span class="c1">Una vez ingresado los datos del GEDO presionando el bot&oacute;n vincular documento, autom&aacute;ticamente pasa a formar parte del EE.</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.90px; height: 86.67px;"><img alt="" src="images/image13.png" style="width: 566.90px; height: 86.67px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c21 c13"><span class="c12"></span></p><p class="c21"><span class="c1">Otra opci&oacute;n para vincular documentos, es mediante la b&uacute;squeda de documentos. presionando el bot&oacute;n &ldquo;B&Uacute;SQUEDA DE DOCUMENTOS&rdquo; se activa el siguiente formulario, que de acuerdo a los filtros seleccionados se habilitan los GEDOS a vincular.</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.90px; height: 269.33px;"><img alt="" src="images/image14.png" style="width: 566.90px; height: 269.33px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c21 c13"><span class="c12"></span></p><p class="c21"><span class="c1">Es importante tener en cuenta que tipos de documentos se van a vincular, actualmente existe un nomenclador que permite identificar los tipos de documentos existentes. En una primera instancia se va a trabajar con los siguiente tipos:</span></p><p class="c21 c13"><span class="c1"></span></p><a id="t.27b1c53aed44faa6bd6168ae2bc5d28e6d28c425"></a><a id="t.1"></a><table class="c42"><tbody><tr class="c38"><td class="c30" colspan="1" rowspan="1"><p class="c4"><span class="c33">C&oacute;d. GEDO</span></p></td><td class="c32" colspan="1" rowspan="1"><p class="c4"><span class="c33">Detalle GEDO</span></p></td><td class="c28 c63" colspan="1" rowspan="1"><p class="c4"><span class="c33">Caracter&iacute;sticas</span></p></td></tr><tr class="c25"><td class="c54" colspan="1" rowspan="1"><p class="c4"><span class="c22">CARGD</span></p></td><td class="c53" colspan="1" rowspan="1"><p class="c4"><span class="c12">Car&aacute;tula GESTDOCU</span></p></td><td class="c28" colspan="1" rowspan="1"><p class="c4"><span class="c12">Se utiliza para digitalizar la car&aacute;tula del expediente f&iacute;sico, es el orden 2 del EE.-</span></p></td></tr><tr class="c38"><td class="c54" colspan="1" rowspan="1"><p class="c4"><span class="c22">NINC</span></p></td><td class="c53" colspan="1" rowspan="1"><p class="c4"><span class="c12">Nota Importada (no comunicable)</span></p></td><td class="c28" colspan="1" rowspan="1"><p class="c4"><span class="c12">Para la digitalizaci&oacute;n de notas dentro del expediente.</span></p></td></tr><tr class="c38"><td class="c54" colspan="1" rowspan="1"><p class="c4"><span class="c22">IFI</span></p></td><td class="c53" colspan="1" rowspan="1"><p class="c4"><span class="c12">Informe Importado</span></p></td><td class="c28" colspan="1" rowspan="1"><p class="c4"><span class="c12">Digitalizaci&oacute;n de informes, vistos buenos, etc.-</span></p></td></tr><tr class="c38"><td class="c54" colspan="1" rowspan="1"><p class="c4"><span class="c22">ANT</span></p></td><td class="c53" colspan="1" rowspan="1"><p class="c4"><span class="c12">Antecedentes</span></p></td><td class="c28" colspan="1" rowspan="1"><p class="c4"><span class="c12">Cualquier documentaci&oacute;n extra que se necesite incorporar al expediente.</span></p></td></tr><tr class="c25"><td class="c54" colspan="1" rowspan="1"><p class="c4"><span class="c22">SPS</span></p></td><td class="c53" colspan="1" rowspan="1"><p class="c4"><span class="c12">SAFIPRO &ndash; Pedido de Suministros</span></p></td><td class="c28" colspan="1" rowspan="1"><p class="c4"><span class="c12">Formulario de pedido de suministros generado desde SAFIPRO</span></p></td></tr></tbody></table><p class="c21 c13"><span class="c12"></span></p><hr style="page-break-before:always;display:none;"><p class="c13 c40" id="h.yifdsfg2elh0"><span class="c19"></span></p><p class="c40" id="h.1intkvirxpth"><span class="c19">PROSECUCI&Oacute;N DEL TR&Aacute;MITE</span></p><p class="c2"><span class="c12"></span></p><p class="c18"><span class="c1">Una vez finalizado el proceso de vinculaci&oacute;n y trabajo sobre el EE estamos en condiciones de darle continuidad al expediente. En la parte inferior del contenido de un EE se encuentra la botonera de acciones para darle continuidad al mismo. </span></p><p class="c18"><span class="c1">Si hemos finalizado el trabajo y consideramos que esta el EE est&aacute; en condiciones de continuar curso, se debe presionar sobre el bot&oacute;n &ldquo;REALIZAR PASE&rdquo;.</span></p><p class="c2"><span class="c1"></span></p><p class="c18"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.90px; height: 37.33px;"><img alt="" src="images/image15.png" style="width: 566.90px; height: 37.33px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c2"><span class="c1"></span></p><p class="c18"><span class="c1">Se activa la pantalla de selecci&oacute;n y formulario de pase del expediente.</span></p><p class="c2"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.90px; height: 452.00px;"><img alt="" src="images/image16.png" style="width: 566.90px; height: 452.00px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c2"><span class="c1"></span></p><p class="c18"><span class="c1">Se deben tener en cuenta las siguientes observaciones.</span></p><ul class="c48 lst-kix_list_3-0 start"><li class="c4 c24 li-bullet-0"><span class="c29">Conocer cu&aacute;l es el mecanismo de recepci&oacute;n de expedientes del remitente, es decir si lo tengo que enviar a un usuario espec&iacute;fico, o si se env&iacute;a a una repartici&oacute;n/sector determinado. Es importante que todas las &aacute;reas notifique adecuadamente el canal de recepci&oacute;n.</span></li><li class="c4 c24 li-bullet-0"><span class="c29">El motivo del pase debe ser breve y lo m&aacute;s claro posible, si es necesario detallar informaci&oacute;n o explayarse sobre las tareas a realizar en el EE se sugiere crear una nota y vincularla al EE, el motivo es meramente informativo.</span></li><li class="c4 c24 li-bullet-0"><span class="c29">El estado del EE debe ser modificado de acuerdo a la acci&oacute;n a realizar, una vez inicializado el mismo al realizar un pr&oacute;ximo pase, el estado debe cambiar a TRAMITACI&Oacute;N, si el EE es enviado a subsanar el estado es SUBSANACI&Oacute;N.</span></li><li class="c21 c24 li-bullet-0"><span class="c1">Una vez realizado un pase, se crea y vincula un documento de tipo PROVIDENCIA autom&aacute;ticamente dentro del EE.</span></li></ul><p class="c0"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.90px; height: 86.67px;"><img alt="" src="images/image17.png" style="width: 566.90px; height: 86.67px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c8 c13"><span class="c12"></span></p><p class="c8 c13"><span class="c12"></span></p><p class="c10" id="h.y83zgn8ze0fl"><span class="c19">VINCULACI&Oacute;N DE PASE EN EXPEDIENTE F&Iacute;SICO</span></p><p class="c10 c13" id="h.lkxvvupz0gd"><span class="c19"></span></p><p class="c21"><span class="c1">Una vez realizado el pase del EE, debe realizarse el pase del Expediente F&iacute;sico, con la vinculaci&oacute;n de la providencia del enviado por GDE. </span></p><p class="c21"><span class="c1">Para esto es importante siempre tener registrado el Nro de EE generado, y realizar la b&uacute;squeda del mismo dentro de la solapa CONSULTAS en el m&oacute;dulo EE.</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.90px; height: 289.33px;"><img alt="" src="images/image18.png" style="width: 566.90px; height: 289.33px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c21 c13"><span class="c1"></span></p><p class="c21"><span class="c1">Dentro del mismo se encuentran todos los filtros disponibles para ubicar un EE, el mas recomendable para ubicar el ultimo trabajado por el usuarios, es la opci&oacute;n &ldquo;Tramitados por Mi&rdquo; y presionando el bot&oacute;n buscar, de esta manera estar&aacute; disponible en la parte inferior todos los EE que fueron tramitados.</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 566.90px; height: 110.67px;"><img alt="" src="images/image19.png" style="width: 566.90px; height: 110.67px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c21 c13"><span class="c1"></span></p><p class="c21"><span class="c1">Una vez localizado el EE se habilita la opci&oacute;n de VISUALIZAR entre las acciones disponibles, logrando ingresar al EE y descargando la &uacute;ltima PROVIDENCIA generada, la cual se puede imprimir y adjuntar en el EE f&iacute;sica con el folio correspondiente.</span></p><p class="c21 c13"><span class="c1"></span></p><p class="c8"><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 283.00px; height: 290.00px;"><img alt="" src="images/image20.png" style="width: 283.00px; height: 290.00px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p><p class="c8"><span>&nbsp;</span><span style="overflow: hidden; display: inline-block; margin: 0.00px 0.00px; border: 0.00px solid #000000; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px); width: 608.77px; height: 86.97px;"><img alt="" src="images/image1.png" style="width: 608.77px; height: 86.97px; margin-left: -0.00px; margin-top: -0.00px; transform: rotate(0.00rad) translateZ(0px); -webkit-transform: rotate(0.00rad) translateZ(0px);" title=""></span></p></body></html>